TriggerOraclev10g.body:
DECLARE
    vro_pago    tkr_pagos%ROWTYPE;
BEGIN
    IF     :new.id IS NOT NULL
       AND pkgtkr_pagos_dao.f_existe (:new.id_pago, vro_pago) = TRUE
    THEN
        vro_pago.id_devolucion := :new.id;
        vro_pago.valor_devuelto := :new.valor_devuelto;
        pkgtkr_pagos_dao.p_actualizar (vro_pago);
    END IF;
END;
